var subject = $input.first().json.subject || '';
var bodyText = $input.first().json.text || '';
var bodyHtml = $input.first().json.html || '';
var emailContent = bodyText || bodyHtml.replace(/<[^>]*>/g, ' ');
var prompt = 'Sei il community manager di una PMI italiana. ';
prompt += 'Hai ricevuto questa notifica email da Google Business Profile per una nuova recensione. ';
prompt += '1) Estrai dal testo: nome recensore, numero stelle da 1 a 5, testo della recensione. ';
prompt += '2) Genera una risposta professionale in italiano di 2-4 frasi. ';
prompt += 'Voto 4-5 stelle: risposta calorosa, cita dettagli del commento, invita a tornare. ';
prompt += 'Voto 1-3 stelle: empatia, scuse sincere, invito a contattarci offline, mai difensivo. ';
prompt += 'Rispondi SOLO con un oggetto JSON con quattro campi: autore, stelle, commento, risposta. ';
prompt += 'CONTENUTO EMAIL: ' + emailContent.substring(0, 3000);
return [{ json: { prompt: prompt, subject: subject } }];

var claudeRaw = $input.first().json.content[0].text;
var subject = $('Gmail - Nuova Recensione').first().json.subject || 'Nuova recensione';
var data = {};
try {
  var txt = claudeRaw.trim();
  var start = txt.indexOf('{');
  var end = txt.lastIndexOf('}');
  if (start !== -1 && end !== -1) { txt = txt.substring(start, end + 1); }
  data = JSON.parse(txt);
} catch(e) {
  data = { autore: 'N/A', stelle: 0, commento: claudeRaw, risposta: claudeRaw };
}
return [{ json: { autore: data.autore || 'N/A', stelle: data.stelle || 0, commento: data.commento || '', risposta: data.risposta || '', subject: subject } }];

var d = $input.first().json;
var tipo = (d.stelle >= 4) ? 'POSITIVA' : 'NEGATIVA';
var today = new Date().toLocaleDateString('it-IT');
var html = '<html><body>';
html += '<h2>Nuova recensione Google - ' + tipo + ' - ' + today + '</h2>';
html += '<table border=1 cellpadding=8>';
html += '<tr><td><b>Recensore</b></td><td>' + d.autore + '</td></tr>';
html += '<tr><td><b>Stelle</b></td><td>' + d.stelle + ' su 5</td></tr>';
html += '<tr><td><b>Commento</b></td><td>' + d.commento + '</td></tr>';
html += '</table>';
html += '<h3>Bozza risposta generata da Claude:</h3>';
html += '<blockquote>' + d.risposta + '</blockquote>';
html += '<p>Copia il testo e incollalo su Google Business Profile per pubblicare la risposta.</p>';
html += '<hr><p><small>n8n Automation Pack Italia - Workflow 05</small></p>';
html += '</body></html>';
var subject = 'Recensione Google ' + tipo + ' - ' + d.stelle + ' stelle - ' + d.autore;
return [{ json: { html: html, subject: subject } }];
